INSERT INTO public.partners (id, key, name, description, tool_count, status, created_at, tools, theme_config, proposed_by, owner_email, logo_svg, contact_person, contact_position, contact_number, contact_email, background)
VALUES
  ('bd5bc1ce-5c2e-4561-a87e-8019af4e4930', 'canva', 'Canva', 'Canva is an online design and visual communication platform offering AI-powered tools (Magic Write, Magic Design, Magic Media) that help teachers and learners create presentations, worksheets, posters, and learning materials with ease.', 0, 'approved', '2026-05-19 01:54:10.233949+00', NULL, '{"accent":"#01A1A7","primary":"#00C4CC","secondary":"#7D2AE8"}'::jsonb, 'be0da6bb-1da6-4b7e-9c79-852d4dc63520', 'marc.cruz@deped.gov.ph', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><defs><clipPath id="clip"><rect width="64" height="64" rx="8"/></clipPath></defs><image href="data:image/png;base64," width="64" height="64" clip-path="url(#clip)" preserveAspectRatio="xMidYMid slice"/></svg>', NULL, NULL, NULL, NULL, NULL),
  ('f58136fe-5b06-4d7b-a8ad-f293ec82de09', 'google', 'Google', 'Google for Education brings Classroom, Workspace for Education, Gemini, and NotebookLM to schools worldwide. These tools support collaborative learning, teacher productivity, and responsible AI use — with enterprise privacy controls suitable for DepEd''s human-in-the-loop governance.', 0, 'approved', '2026-05-19 01:34:51.241822+00', NULL, '{"accent":"#EA4335","primary":"#4285F4","secondary":"#34A853"}'::jsonb, 'be0da6bb-1da6-4b7e-9c79-852d4dc63520', 'marc.cruz@deped.gov.ph', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><defs><clipPath id="clip"><rect width="64" height="64" rx="8"/></clipPath></defs><image href="data:image/png;base64," width="64" height="64" clip-path="url(#clip)" preserveAspectRatio="xMidYMid slice"/></svg>', NULL, NULL, NULL, NULL, NULL),
  ('4ae348d5-921d-460f-977d-1aeb881d664d', 'khan-academy', 'Khan Academy', 'Khan Academy is a non-profit providing free, world-class education for anyone, anywhere. Its AI tutor Khanmigo offers Socratic, student-safe guidance across math, science, reading, and writing — well aligned with DepEd''s mission of equitable access to quality basic education.', 0, 'approved', '2026-05-19 01:34:51.241822+00', NULL, '{"accent":"#21242C","primary":"#14BF96","secondary":"#0A2A66"}'::jsonb, 'be0da6bb-1da6-4b7e-9c79-852d4dc63520', 'marc.cruz@deped.gov.ph', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><defs><clipPath id="clip"><rect width="64" height="64" rx="8"/></clipPath></defs><image href="data:image/png;base64," width="64" height="64" clip-path="url(#clip)" preserveAspectRatio="xMidYMid slice"/></svg>', NULL, NULL, NULL, NULL, NULL),
  ('190f9e0b-5c2d-439e-b498-21785c195bb0', 'microsoft', 'Microsoft', 'Microsoft Education provides Microsoft 365 for Education, Teams, Reading Coach, and Copilot for educators and students. Its AI capabilities support literacy growth, accessibility, and teacher workflows under strict data protection standards aligned with DepEd compliance expectations.', 0, 'approved', '2026-05-19 01:34:51.241822+00', NULL, '{"accent":"#00A4EF","primary":"#F25022","secondary":"#FFB900"}'::jsonb, 'be0da6bb-1da6-4b7e-9c79-852d4dc63520', 'marc.cruz@deped.gov.ph', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><defs><clipPath id="clip"><rect width="64" height="64" rx="8"/></clipPath></defs><image href="data:image/png;base64," width="64" height="64" clip-path="url(#clip)" preserveAspectRatio="xMidYMid slice"/></svg>', NULL, NULL, NULL, NULL, NULL),
  ('78ae48c6-6719-481d-ac6f-b82871ed42ea', 'office-of-the-assistant-secretary-of-strategic-management', 'Office of the Assistant Secretary of Strategic Management', 'In-charge for the Education Futures Office', 0, 'approved', '2026-05-19 08:02:39.337174+00', NULL, '{"accent":"#EEB328","primary":"#034F8B","secondary":"#E11C38"}'::jsonb, '923546c7-a78b-4756-a4f3-fa8dd7021770', 'oassm@deped.gov.ph', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><defs><clipPath id="clip"><rect width="64" height="64" rx="8"/></clipPath></defs><image href="data:image/png;base64," width="64" height="64" clip-path="url(#clip)" preserveAspectRatio="xMidYMid slice"/></svg>', NULL, NULL, NULL, NULL, NULL),
  ('83f8e679-4a87-4a79-aa3e-4c24762eaea1', 'openai', 'OpenAI', 'OpenAI is an AI research and deployment company behind ChatGPT, GPT-4o, and a suite of APIs widely used in education. For DepEd contexts, OpenAI tools can support lesson planning, formative feedback, language learning, and accessibility — always with human-in-the-loop review and no use of real learner data.', 0, 'approved', '2026-05-19 01:34:51.241822+00', NULL, '{"accent":"#343541","primary":"#ECECF1","secondary":"#10A37F"}'::jsonb, 'be0da6bb-1da6-4b7e-9c79-852d4dc63520', 'marc.cruz@deped.gov.ph', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><defs><clipPath id="clip"><rect width="64" height="64" rx="8"/></clipPath></defs><image href="data:image/png;base64," width="64" height="64" clip-path="url(#clip)" preserveAspectRatio="xMidYMid slice"/></svg>', NULL, NULL, NULL, NULL, NULL),
  ('efadea2e-6aef-4676-ae7c-5e72524e3126', 'ecair', 'E-CAIR', 'Educational Center for AI Resources (E-CAIR) — DepEd''s in-house initiative to develop, curate, and govern AI-powered tools that support Philippine basic education. E-CAIR ensures every tool is safe, ethical, and aligned with the K to 12 curriculum.', 0, 'approved', '2026-05-28 02:32:02.089861+00', NULL, '{"accent":"#B91C1C","primary":"#1E3A8A","secondary":"#6B1F5C"}'::jsonb, NULL, NULL, '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><defs><clipPath id="clip"><rect width="64" height="64" rx="8"/></clipPath></defs><image href="data:image/png;base64," width="64" height="64" clip-path="url(#clip)" preserveAspectRatio="xMidYMid slice"/></svg>', 'E-CAIR Team', 'Educational Center for AI Resources', NULL, 'ecair@deped.gov.ph', NULL)
