INSERT INTO public.partner_tool_details (id, partner_id, tool_name, risk_classification, intended_use, privacy_impact_assessment, compliance_assessment, responsible_officer, oversight_mechanism, created_at, updated_at, risk_approved, risk_approved_by, risk_approved_at, tool_url, description, tool_objective, target_users, estimated_users, use_case, budget, tech_requirements, training_required, tool_logo_svg)
VALUES
  ('7894b2a4-8acd-46da-bc6d-d61d56dac4d4', 'efadea2e-6aef-4676-ae7c-5e72524e3126', 'SABAY', 'High', 'Support identification and screening of learners with disabilities for inclusive education.', 'Pending evaluation against DepEd AI policy; Microsoft indicates compliance with GDPR and ISO/IEC standards.', NULL, NULL, NULL, '2026-05-28 03:06:30.715023+00', '2026-05-28 03:06:30.715023+00', TRUE, '04887346-7e04-4158-b246-2e78515383c6', '2026-05-29 02:00:41.121+00', NULL, 'Enhanced Screening of Learners with Disabilities.', NULL, NULL, NULL, NULL, NULL, NULL, 'needed', NULL),
  ('105e034e-3a50-4b95-8a77-95d2ebf3c0a7', '78ae48c6-6719-481d-ac6f-b82871ed42ea', 'Project ALAM', 'Minimal', 'Project ALAM Regional Version is a Chatbot that can answer questions about regional level data official RDO data. It serves to consolidate and assess regional data for validation before collecting to the main database.', 'Pending evaluation against DepEd AI policy; Microsoft indicates compliance with GDPR and ISO/IEC standards.', NULL, NULL, 'test', '2026-05-28 03:31:57.959759+00', '2026-05-28 03:31:57.959759+00', TRUE, '04887346-7e04-4158-b246-2e78515383c6', '2026-05-29 02:01:09.666+00', NULL, 'ALAM works by reading and understanding various data sources (BEIS, LIS,Stride and more) and local and central memos that are uploaded to the system. Uploaded data and memos are being used as knowledge and uses Artificial Intelligence (AI) to understand prompts and questions and use the uploaded data. It uses semantic search and retrieval-augmented generation (RAG) through its knowledge to produce the output needed corresponding to the prompt', 'Make school data easy to find – no need to dig through spreadsheets or files.
Give fast, accurate answers based on real documents.
Help DepEd staff, researchers, and the public get reliable information anytime.
Reduce manual work and human error in handling school records.
', 'DepED Regional Office', NULL, 'test', 'n/a', 'React 18, TypeScript, Vite, Tailwind CSS, shadcn/ui, Framer Motion, Supabase managed Postgres database, authentication, file storage, Postgres tsvector full-text search, Row-Level Security (RLS) policies, Supabase JavaScript SDK, SheetJS and PDF parsing libraries for dataset ingestion, and Vercel-grade hosting', 'needed', NULL),
  ('4d7701c1-bba5-4087-8eb5-4899ccb14f23', 'efadea2e-6aef-4676-ae7c-5e72524e3126', 'PAARAL', 'Limited', 'Optimize allocation of government assistance and subsidies in basic education through advanced analytics.', 'Pending evaluation against DepEd AI policy; Microsoft indicates compliance with GDPR and ISO/IEC standards.', NULL, NULL, NULL, '2026-05-28 03:06:30.715023+00', '2026-05-28 03:06:30.715023+00', TRUE, '04887346-7e04-4158-b246-2e78515383c6', '2026-05-29 02:00:37.332+00', NULL, 'Advanced Analytics for Optimizing Government Assistance and Subsidies in Basic Education.', NULL, NULL, NULL, NULL, NULL, NULL, 'needed', NULL),
  ('96b7f58e-26ff-4116-864c-ed1e324156c8', 'efadea2e-6aef-4676-ae7c-5e72524e3126', 'DUNONG', 'Limited', 'Analyze NQESH data to support school principals and leadership development.', 'Pending evaluation against DepEd AI policy; Microsoft indicates compliance with GDPR and ISO/IEC standards.', NULL, NULL, NULL, '2026-05-28 03:06:30.715023+00', '2026-05-28 03:06:30.715023+00', TRUE, '04887346-7e04-4158-b246-2e78515383c6', '2026-05-29 02:01:14.516+00', NULL, 'School Principals NQESH Data Analytics.', NULL, NULL, NULL, NULL, NULL, NULL, 'needed', NULL),
  ('f2a24258-95ed-4148-bda8-be51be192e89', 'efadea2e-6aef-4676-ae7c-5e72524e3126', 'SIGLA', 'High', 'Screen learners for stunting and underweight conditions using AI-powered analysis.', 'Pending evaluation against DepEd AI policy; Microsoft indicates compliance with GDPR and ISO/IEC standards.', NULL, NULL, NULL, '2026-05-28 03:06:30.715023+00', '2026-05-28 03:06:30.715023+00', TRUE, '04887346-7e04-4158-b246-2e78515383c6', '2026-05-29 02:01:03.944+00', NULL, 'AI-powered Screening of Stunted and Underweight Learners.', NULL, NULL, NULL, NULL, NULL, NULL, 'needed', NULL),
  ('7c4c4bc0-8671-4342-88fa-5527714a2f42', 'efadea2e-6aef-4676-ae7c-5e72524e3126', 'TALINO', 'Minimal', 'Match school needs with donors under the Adopt-A-School Program.', 'Pending evaluation against DepEd AI policy; Microsoft indicates compliance with GDPR and ISO/IEC standards.', NULL, NULL, NULL, '2026-05-28 03:06:30.715023+00', '2026-05-28 03:06:30.715023+00', TRUE, '04887346-7e04-4158-b246-2e78515383c6', '2026-05-29 02:01:23.074+00', NULL, 'Mapping of School Needs and Donors for the Adopt-A-School Program.', NULL, NULL, NULL, NULL, NULL, NULL, 'needed', NULL),
  ('bf41d8b4-4576-4729-86c0-c2dd12f3c7e0', 'efadea2e-6aef-4676-ae7c-5e72524e3126', 'SALIKSEEK', 'Limited', 'Provide quick, AI-assisted responses to frequently asked questions using GenAI agents.', 'Pending evaluation against DepEd AI policy; Microsoft indicates compliance with GDPR and ISO/IEC standards.', NULL, NULL, NULL, '2026-05-28 03:06:30.715023+00', '2026-05-28 03:06:30.715023+00', TRUE, '04887346-7e04-4158-b246-2e78515383c6', '2026-05-29 02:00:44.434+00', NULL, 'Quick Response Tool to FAQs with GenAI Agents.', NULL, NULL, NULL, NULL, NULL, NULL, 'needed', NULL),
  ('cd045013-30e3-421f-8c2d-87b8ae6d11b3', 'efadea2e-6aef-4676-ae7c-5e72524e3126', 'LIGTAS', 'Limited', 'Map and analyze natural hazard risks affecting schools for safety planning.', 'Pending evaluation against DepEd AI policy; Microsoft indicates compliance with GDPR and ISO/IEC standards.', NULL, NULL, NULL, '2026-05-28 03:06:30.715023+00', '2026-05-28 03:06:30.715023+00', TRUE, '04887346-7e04-4158-b246-2e78515383c6', '2026-05-29 02:01:18.446+00', NULL, 'Geospatial Analysis and Mapping of Natural Hazard Risks in Schools.', NULL, NULL, NULL, NULL, NULL, NULL, 'needed', NULL),
  ('e4bd5bcc-3b23-4bcb-a74e-7fe808d241d4', 'f58136fe-5b06-4d7b-a8ad-f293ec82de09', 'Google Gemini', 'High', 'Administrative drafting, report generation, teacher workload reduction (document prep). Not for automated student assessment.', 'Pending evaluation against DepEd AI policy; claimed compliance with international AI governance frameworks.', NULL, NULL, 'Teacher or staff must review generated content; AI not allowed to provide final learning assessments.', '2026-06-01 06:24:27.855122+00', '2026-06-01 06:24:27.855122+00', TRUE, 'be0da6bb-1da6-4b7e-9c79-852d4dc63520', '2026-06-02 01:03:29.486+00', 'https://gemini.google.com/app', 'Generative AI model integrated into Google Workspace and search; used for drafting, summarization, data analysis, and multilingual support.', 'Google Gemini''s primary objective is to be a highly capable, multimodal artificial intelligence model designed to understand and operate across different types of information seamlessly—including text, code, audio, image, and video. Rather than just being a text-based chatbot, its goal is to act as a versatile, natively multimodal foundational model that can reason complexly, solve advanced problems, and be integrated across Google''s entire ecosystem of products (like Search, Docs, and Pixel devices) to enhance human productivity and creativity.', 'Students, teachers and employees', NULL, 'The Department of Education (DepEd) can utilize the ALAM system as a powerful data intelligence and policy augmentation tool to streamline governance and improve institutional efficiency. Planning officers and regional directors can use its plain-language query interface to bypass hours of manual data aggregation, instantly generating synthesized, evidence-grounded insights on complex issues like teacher shortages, infrastructure gaps, or localized enrollment trends. Because the system utilizes a "deterministic-first" architecture, administrators can reliably cite its hard data points and metrics during high-stakes planning meetings, confident that the numbers are queried directly from verified fact tables rather than generated by a predictive AI model. FurtheThe Department of Education (DepEd) can strategically utilize Google Gemini to modernize classroom learning, optimize teacher workflows, and improve education governance following its foundational AI guidelines (Department Order No. 003, Series of 2026). Through DepEd''s massive deployment of Google Workspace for Education Plus accounts to over one million teachers and staff, educators can leverage Gemini directly within Google Workspace tools to drastically cut down administrative workloads. ', NULL, NULL, 'needed', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><defs><clipPath id="clip"><rect width="64" height="64" rx="12"/></clipPath></defs><image href="data:image/png;base64," width="64" height="64" clip-path="url(#clip)" preserveAspectRatio="xMidYMid slice"/></svg>'),
  ('bab7de07-2130-4804-8772-cdc7e1076834', '190f9e0b-5c2d-439e-b498-21785c195bb0', 'Microsoft Copilot', 'Minimal', 'Administrative drafting, report generation, teacher workload reduction (document prep). Not for automated student assessment.', 'Pending evaluation against DepEd AI policy; Microsoft indicates compliance with GDPR and ISO/IEC standards.', NULL, NULL, 'Staff validate outputs; sensitive data requires manual redaction before AI use.', '2026-06-01 06:28:11.468973+00', '2026-06-01 06:28:11.468973+00', TRUE, 'be0da6bb-1da6-4b7e-9c79-852d4dc63520', '2026-06-02 03:36:16.959+00', 'https://m365.cloud.microsoft/chat', 'AI productivity assistant embedded in Microsoft 365 for drafting documents, summarizing emails, generating presentations, and code assistance.', 'Microsoft Copilot is designed to serve as a versatile, everyday AI companion that seamlessly integrates across various digital environments to enhance user productivity and streamline routine tasks. Its objective is to assist individuals and organizations by transforming natural language prompts into actionable outputs, helping users navigate information, generate diverse content, and optimize workflows. By acting as an intuitive conversational layer within an established ecosystem of applications, it aims to reduce cognitive friction and empower users to achieve greater efficiency in their daily digital interactions.', NULL, NULL, 'Within the Department of Education (DepEd), Microsoft Copilot serves as an integrated administrative assistant designed to optimize day-to-day office workflows and reduce manual overhead. Operating natively across the agency’s standard productivity software, the tool can instantly synthesize lengthy regional reports into brief executive summaries, draft formal official correspondence from rough bullet points, and automatically generate structured action items from meeting transcripts. By handling these repetitive compilation and documentation tasks, it allows education personnel and division staff to focus less on paperwork and more on strategic planning and direct institutional support.', NULL, NULL, 'needed', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><defs><clipPath id="clip"><rect width="64" height="64" rx="12"/></clipPath></defs><image href="data:image/png;base64," width="64" height="64" clip-path="url(#clip)" preserveAspectRatio="xMidYMid slice"/></svg>'),
  ('a11ff699-9950-4761-923b-aa58ca371a73', 'bd5bc1ce-5c2e-4561-a87e-8019af4e4930', 'Canva Magic Write', 'Limited', 'Drafting lesson plan outlines, brainstorming project ideas, refining grammar on presentations, or generating reading comprehension questions.', 'Falls under Limited Risk. Requires a Privacy Impact Assessment (PIA) at the institutional level. Users must not input sensitive personal information (SPI) or confidential student records into the prompt to prevent data leaks, complying with the Data Privacy Act of 2012.', 'Requires a Privacy Impact Assessment (PIA) at the institutional level. Users must not input sensitive personal information (SPI) or confidential student records into the prompt to prevent data leaks, complying with the Data Privacy Act of 2012.', NULL, 'AI must function strictly as an auxiliary tool. Teachers must independently validate the accuracy and pedagogical soundness of any generated educational materials. Students are required to disclose their use of Magic Write and provide proper citations for their outputs to maintain academic integrity.', '2026-06-02 07:49:55.958755+00', '2026-06-02 07:49:55.958755+00', TRUE, 'be0da6bb-1da6-4b7e-9c79-852d4dc63520', '2026-06-02 23:49:58.593+00', NULL, 'An AI-powered text generation tool integrated into Canva’s text boxes and documents, capable of drafting, summarizing, and rewriting content.', 'To overcome writer''s block, accelerate the drafting process, and assist with grammar and tone adjustments.', 'Teachers, non-teaching personnel, and independent learners (Junior and Senior High School). Direct use by K-3 learners is restricted without strict adult supervision.', NULL, 'A teacher generating a draft rubric for an upcoming science fair, or a Grade 11 student brainstorming arguments for a debate presentation.', 'n/a', 'N/a', 'none', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><defs><linearGradient id="gy48b8d" x1="0" y1="0" x2="1" y2="1"><stop offset="0%" stop-color="#00C4CC"/><stop offset="100%" stop-color="#7D2AE8"/></linearGradient></defs><rect width="64" height="64" rx="14" fill="url(#gy48b8d)"/><circle cx="48" cy="16" r="6" fill="#01A1A7" fill-opacity="0.75"/><text x="32" y="40" text-anchor="middle" font-family="Inter, ui-sans-serif, system-ui, sans-serif" font-weight="700" font-size="24" fill="#ffffff">CW</text></svg>'),
  ('68fc0275-f6df-430a-9f27-fab772c43f26', '4ae348d5-921d-460f-977d-1aeb881d664d', 'Khanmigo', 'Limited', 'To serve as a guided study assistant for students during independent learning or homework sessions, and as a curriculum-aligned drafting tool for teachers to create lesson plans, rubrics, and discussion prompts.', 'Classified as Limited Risk AI with specific child-safety guardrails. Because it functions as an interactive chatbot for minors, a comprehensive Privacy Impact Assessment (PIA) must be maintained. The tool includes integrated safety filters that flag inappropriate language, self-harm keywords, or breaches of academic integrity. In strict compliance with the Data Privacy Act of 2012, no Sensitive Personal Information (SPI), learner home addresses, or confidential academic records should be inputted into the chat environment.', NULL, NULL, 'Teachers maintain total oversight. Khanmigo acts strictly as an auxiliary tutor; the teacher remains the sole authority for evaluating student performance, assigning official grades, and driving classroom instruction. Teachers also have access to student chat logs to monitor progress and safety.', '2026-06-02 23:49:47.326668+00', '2026-06-02 23:49:47.326668+00', TRUE, 'be0da6bb-1da6-4b7e-9c79-852d4dc63520', '2026-06-02 23:50:16.019+00', 'https://www.khanmigo.ai/', 'An AI-powered virtual tutor for learners and a pedagogical assistant for educators. Powered by large language models, it uses a Socratic, guided-learning approach to help students solve problems across various subjects without directly giving them the answers, while providing teachers with lesson-planning and content-generation tools.', 'To deliver personalized, scalable learning support and immediate feedback to students while reducing the administrative and preparatory workload for teachers, effectively acting as an interactive teaching and learning co-pilot.', 'Teachers and Learners', NULL, 'A Junior High School student struggling with a complex mathematics equation chats with Khanmigo, which asks guided questions to help the student identify their own mistake. Simultaneously, a teacher uses Khanmigo’s backend to quickly generate a differentiated rubric for a science lab report based on specific DepEd learning competencies.', 'n/a', 'n/a', 'needed', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><defs><clipPath id="clip"><rect width="64" height="64" rx="12"/></clipPath></defs><image href="data:image/png;base64," width="64" height="64" clip-path="url(#clip)" preserveAspectRatio="xMidYMid slice"/></svg>')
